func TestDeque_StealTop(t *testing.T) {
	d := NewDeque()
	d.PushBottom("a")
	d.PushBottom("b")
	d.PushBottom("c")
	v, ok := d.StealTop()
	if !ok || v != "a" {
		t.Fatal("stealTop should return first pushed (FIFO)")
	}
}

func TestDeque_MixedOps(t *testing.T) {
	d := NewDeque()
	d.PushBottom("a")
	d.PushBottom("b")
	d.PushBottom("c")
	d.StealTop()  // removes a
	d.PopBottom() // removes c
	v, ok := d.PopBottom()
	if !ok || v != "b" {
		t.Fatalf("expected b, got %v", v)
	}
