	p.Submit("w2", "c")
	if p.TotalPending() != 3 {
		t.Fatalf("expected 3, got %d", p.TotalPending())
	}
}

func TestWSP_StolenCount(t *testing.T) {
	p := NewWorkStealingPool()
	p.Register("w1")
	p.Register("w2")
