   144	// RunGossipRound executes one round of gossip for all nodes.
   145	// Each node picks fanout peers and performs push-pull, subject to
   146	// network conditions (partitions, packet loss).
   147	func (ns *NetworkSim) RunGossipRound() SimRoundResult {
   148		ns.mu.Lock()
   149		defer ns.mu.Unlock()
   150		ns.clock++
   151	
   152		var result SimRoundResult
   153		peerList := ns.peerList()
   154	
   155		for nodeID, proto := range ns.nodes {
   156			sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
   157			peers := sel.SelectPeers(peerList, nodeID, proto.Fanout())
   158	
   159			for _, peerID := range peers {
   160				if ns.isPartitioned(nodeID, peerID) {
   161					result.Blocked++
   162					continue
   163				}
   164				if ns.dropRate > 0 && ns.rng.Float64() < ns.dropRate {
   165					result.Dropped++
   166					continue
   167				}
   168				peerStore, ok := ns.stores[peerID]
   169				if !ok {
   170					continue
   171				}
   172				exchange := proto.PushPull(peerStore)
   173				result.Exchanges++
   174				result.PushedTotal += exchange.PushedTo
   175				result.PulledTotal += exchange.PulledFrom
   176	
   177				ns.recordEvent(Event{
   178					Time:    ns.clock,
   179					Type:    EventGossip,
   180					Source:  nodeID,
   181					Target:  peerID,
   182					Payload: exchange,
   183				})
   184			}
   185		}
   186		return result
   187	}
