   189	// RunMerkleSyncRound performs merkle-based anti-entropy between random pairs.
   190	func (ns *NetworkSim) RunMerkleSyncRound() int {
   191		ns.mu.Lock()
   192		defer ns.mu.Unlock()
   193		ns.clock++
   194	
   195		synced := 0
   196		peerList := ns.peerList()
   197		if len(peerList) < 2 {
   198			return 0
   199		}
   200	
   201		for nodeID, store := range ns.stores {
   202			// Pick a random peer
   203			sel := gossip.NewRandomPeerSelector(ns.rng.Int63())
   204			peers := sel.SelectPeers(peerList, nodeID, 1)
   205			if len(peers) == 0 {
   206				continue
   207			}
   208			peerID := peers[0]
   209			if ns.isPartitioned(nodeID, peerID) {
   210				continue
   211			}
   212	
   213			peerStore, ok := ns.stores[peerID]
   214			if !ok {
   215				continue
   216			}
   217	
   218			// Build merkle trees from both stores
   219			localTree := storeToTree(store)
   220			remoteTree := storeToTree(peerStore)
   221			diff := merkle.FastDiff(localTree, remoteTree)
   222	
   223			// Sync differing keys using Apply to preserve versions
   224			for _, key := range diff.OnlyRemote {
   225				e, ok := peerStore.GetEntry(key)
   226				if ok {
   227					store.Apply([]*gossip.StateEntry{e})
   228					synced++
   229				}
   230			}
   231			for _, key := range diff.OnlyLocal {
   232				e, ok := store.GetEntry(key)
   233				if ok {
   234					peerStore.Apply([]*gossip.StateEntry{e})
   235					synced++
   236				}
   237			}
   238			for _, key := range diff.Different {
   239				le, _ := store.GetEntry(key)
   240				re, _ := peerStore.GetEntry(key)
   241				if le != nil && re != nil {
   242					if le.Version > re.Version {
   243						peerStore.Apply([]*gossip.StateEntry{le})
   244					} else {
   245						store.Apply([]*gossip.StateEntry{re})
   246					}
   247					synced++
   248				}
   249			}
   250	
   251			ns.recordEvent(Event{
   252				Time:    ns.clock,
   253				Type:    EventMerkleDiff,
   254				Source:  nodeID,
   255				Target:  peerID,
   256				Payload: diff.TotalDiffs(),
   257			})
   258		}
   259		return synced
   260	}
   261	
   262	func storeToTree(store *gossip.StateStore) *merkle.Tree {
   263		tree := merkle.NewTree()
   264		entries := make(map[string][]byte)
   265		for _, key := range store.Keys() {
   266			v, ok := store.Get(key)
   267			if ok {
   268				entries[key] = v
   269			}
   270		}
   271		tree.PutBatch(entries)
   272		return tree
   273	}
