   293	// Converged checks if all nodes have the same state hash.
   294	func (ns *NetworkSim) Converged() bool {
   295		ns.mu.Lock()
   296		defer ns.mu.Unlock()
   297		var firstHash [32]byte
   298		first := true
   299		for _, store := range ns.stores {
   300			h := store.Hash()
   301			if first {
   302				firstHash = h
   303				first = false
   304			} else if h != firstHash {
   305				return false
   306			}
   307		}
   308		return true
   309	}
